function roleLabel(role) {
    if (role === "system") {
        return "SYSTEM";
    }
    if (role === "assistant") {
        return "ASSISTANT";
    }
    return "USER";
}
export function renderCliPrompt(messages) {
    const body = messages
        .map((message) => `${roleLabel(message.role)}:\n${message.content.trim()}`)
        .join("\n\n");
    return `${body}\n\nASSISTANT:\n`;
}
